class Solution:
    def scoreOfString(self, s):
        codes = [ord(c) for c in s]
        return sum(abs(codes[i] - codes[i + 1]) for i in range(len(codes) - 1))

solutions.python:
class Solution:
    def scoreOfString(self, s):
        total = 0
        for i in range(1, len(s)):
            total += abs(ord(s[i]) - ord(s[i - 1]))
        return total

